        "body": "={{ JSON.stringify({ query: `mutation { change_column_value(board_id: BOARD_ID, item_id: \"${$('Code: Extraer campos').item.json.monday_item_id}\", column_id: \"text_media_id\", value: \"${$json.id}\") { id } }` }) }}"
