              "renameOutput": true, "outputKey": "VEMARE"
            },
            {
              "conditions": { "conditions": [{ "leftValue": "={{ $json.empresa }}", "rightValue": "TRANSCOSE", "operator": { "type": "string", "operation": "equals" } }], "combinator": "and" },
