        "jsCode": "// EQUIPO: teléfonos internos — MODIFICAR CON LOS REALES\nconst ctx = $('Code: Prep contexto enc').item.json;\nconst equipo = [\n  { telefono_wa: '34600000001', razon_social: 'Equipo WA 1', codigo_isi: null },\n  { telefono_wa: '34600000002', razon_social: 'Equipo WA 2', codigo_isi: null }\n];\nreturn equipo.map(c => ({ json: { ...ctx, ...c } }));"
