      "parameters": {
        "jsCode": "// Modo REAL_MANUAL: descargar CSV de monday y parsear\n// El asset_id viene de 'Code: Extraer campos'\nconst ctx = $('Code: Prep contexto enc').item.json;\n\n// Aquí se usa el nodo HTTP para descargar el CSV (ver notas)\n// Por ahora retornamos el contexto para que el siguiente nodo HTTP lo descargue\nreturn [{ json: { ...ctx, _needs_csv_download: true } }];"
