        "responseBody": "ok"
      }
    },
    {
      "id": "b2c3d4e5-0003-0003-0003-000000000003",
      "name": "Code: Validar firma X-Hub",
      "type": "n8n-nodes-base.code",
      "typeVersion": 2,
      "position": [200, 400],
      "parameters": {
        "jsCode": "const crypto    = require('crypto');\nconst payload   = JSON.stringify($json.body);\nconst signature = $json.headers['x-hub-signature-256'];\nconst secret    = $env.WA_APP_SECRET;\n\nif (!secret) throw new Error('WA_APP_SECRET no configurado en el entorno de n8n');\n\nconst expected = 'sha256=' + crypto\n  .createHmac('sha256', secret)\n  .update(payload)\n  .digest('hex');\n\nif (!signature || signature !== expected) {\n  throw new Error('X-Hub-Signature-256 inválida — request rechazado');\n}\n\nreturn $input.all();"
      }
    },
    {
      "id": "b2c3d4e5-0004-0004-0004-000000000004",
      "name": "Code: Normalizar mensaje",
      "type": "n8n-nodes-base.code",
      "typeVersion": 2,
      "position": [440, 400],
      "parameters": {
        "jsCode": "const entry   = $json.body?.entry?.[0];\nconst change  = entry?.changes?.[0]?.value;\n\n// Verificar si es un status (delivery) vs mensaje\nif (change?.statuses) {\n  return [{ json: { _tipo_evento: 'status', ...change.statuses[0] } }];\n}\n\nconst msg  = change?.messages?.[0];\nif (!msg) return [{ json: { _tipo_evento: 'otro' } }];\n\nconst tipo = msg.type;\nlet text_content     = '';\nlet flow_response    = null;\nlet flow_token       = '';\nlet is_flow_response = false;\n\nif (tipo === 'interactive') {\n  const ia = msg.interactive;\n  if (ia?.type === 'button_reply') {\n    text_content = ia.button_reply.id;\n  } else if (ia?.type === 'nfm_reply') {\n    flow_response    = JSON.parse(ia.nfm_reply.response_json);\n    flow_token       = flow_response.flow_token ?? '';\n    text_content     = 'nfm_reply';\n    is_flow_response = true;\n  }\n} else if (tipo === 'text') {\n  text_content = msg.text?.body?.toLowerCase().trim() || '';\n}\n\nreturn [{\n  json: {\n    _tipo_evento:    'mensaje',\n    waid:            msg.from,\n    db_phone:        msg.from,\n    text_content,\n    flow_response,\n    flow_token,\n    is_flow_response\n  }\n}];"
      }
    },
    {
      "id": "b2c3d4e5-0005-0005-0005-000000000005",
      "name": "Switch: tipo evento",
      "type": "n8n-nodes-base.switch",
      "typeVersion": 3.2,
      "position": [680, 400],
      "parameters": {
