              "renameOutput": true, "outputKey": "nfm_reply"
            },
            {
              "conditions": { "conditions": [{ "leftValue": "={{ $json._tipo_evento }}", "rightValue": "mensaje", "operator": { "type": "string", "operation": "equals" } }], "combinator": "and" },
              "renameOutput": true, "outputKey": "chatbot"
            }
          ]
        },
        "fallbackOutput": "extra"
      }
    },
    {
      "id": "b2c3d4e5-0006-0006-0006-000000000006",
      "name": "PG: Lookup por wa_flow_token",
      "type": "n8n-nodes-base.postgres",
      "typeVersion": 2.5,
