        "query": "SELECT ew.id, ew.id_campana, ew.codigo_isi, ew.razon_social, ew.telefono_wa,\n       ew.wa_flow_token,\n       cw.codigo_encuesta, cw.version_num, cw.codigo_empresa, cw.id_externo_collector\nFROM encuestas.envios_wa ew\nJOIN encuestas.campanas_wa cw ON cw.id = ew.id_campana\nWHERE ew.wa_flow_token = $1::uuid",
