        "operation": "executeQuery",
        "query": "SELECT\n  p.codigo_pregunta,\n  p.id_externo_pregunta,\n  p.orden,\n  lm.codigo_metrica,\n  pv.peso_final_calculado,\n  pv.version_num\nFROM maestro.encuestas_maestro em\nJOIN maestro.preguntas_maestro p\n  ON p.id_encuesta = em.id_encuesta AND p.pregunta_activa = true\nJOIN maestro.lista_metricas lm\n  ON lm.id_metrica = p.id_metrica\nJOIN maestro.ponderaciones_versiones pv\n  ON pv.id_encuesta = em.id_encuesta\n  AND pv.version_num = $2\n  AND pv.id_pregunta = p.id_pregunta\nWHERE em.codigo_encuesta = $1\nORDER BY p.orden",
        "additionalFields": {
