      "type": "n8n-nodes-base.code",
      "typeVersion": 2,
      "position": [1880, 360],
      "parameters": {
        "jsCode": "// Tomar datos del lookup y de los mapas\nconst envio     = $('PG: Lookup por wa_flow_token').item.json;\nconst preguntas = $('PG: Mapa preguntas y pesos').all().map(i => i.json);\nconst opciones  = $('PG: Mapa opciones').all().map(i => i.json);\nconst flowResponse = $('Code: Normalizar mensaje').item.json.flow_response;\n\nif (!preguntas.length) {\n  throw new Error(`Sin preguntas en maestro para encuesta: ${envio.codigo_encuesta} v${envio.version_num}`);\n}\n\nconst filas = preguntas.map(pregunta => {\n  const valor_raw    = flowResponse[pregunta.id_externo_pregunta];\n  const esComentario = pregunta.codigo_metrica === 'COMENTARIO';\n\n  let valor_numerico        = null;\n  let valor_calculado       = null;\n  let respuesta_comentario  = null;\n\n  if (esComentario) {\n    respuesta_comentario = valor_raw ?? null;\n  } else {\n    const opcion = opciones.find(\n      o => o.codigo_pregunta === pregunta.codigo_pregunta && o.id_externo_opcion === valor_raw\n    );\n    valor_numerico  = opcion?.valor_numerico != null ? parseFloat(opcion.valor_numerico) : null;\n    const peso      = parseFloat(pregunta.peso_final_calculado || 0);\n    valor_calculado = (valor_numerico !== null && peso > 0)\n      ? parseFloat((valor_numerico * peso).toFixed(4))\n      : null;\n  }\n\n  return {\n    json: {\n      id_campana:           envio.id_campana,\n      id_envio:             envio.id,\n      codigo_encuesta:      envio.codigo_encuesta,\n      version_num:          envio.version_num,\n      codigo_pregunta:      pregunta.codigo_pregunta,\n      id_grupo_respuesta:   envio.wa_flow_token,\n      codigo_isi:           envio.codigo_isi,\n      razon_social:         envio.razon_social,\n      codigo_metrica:       pregunta.codigo_metrica,\n      peso_final_calculado: parseFloat(pregunta.peso_final_calculado || 0),\n      valor_numerico,\n      valor_calculado,\n      respuesta_comentario,\n      atributos_adicionales: JSON.stringify({\n        id_externo_pregunta: pregunta.id_externo_pregunta,\n        raw_value: valor_raw\n      }),\n      // para mutations monday\n      id_externo_collector: envio.id_externo_collector\n    }\n  };\n});\n\nreturn filas;"
      }
