        "sendBody": true,
        "contentType": "json",
        "body": "={{ JSON.stringify({ query: `query { boards(ids: [BOARD_ID]) { items_page(limit: 100, query_params: { rules: [{ column_id: \"status_wa\", compare_value: [\"ENVIADA\",\"ENVIANDO\"], operator: any_of }] }) { items { id name column_values { id text } } } } }` }) }}"
      },
      "credentials": {
