      "name": "Code: Extraer items",
      "type": "n8n-nodes-base.code",
      "typeVersion": 2,
      "position": [480, 300],
      "parameters": {
        "jsCode": "const items = $json.data?.boards?.[0]?.items_page?.items || [];\nreturn items.map(item => {\n  const cols = {};\n  item.column_values.forEach(c => { cols[c.id] = c.text; });\n  return {\n    json: {\n      monday_item_id: item.id,\n      titulo: item.name,\n      tipo: (cols.tipo_comunicacion || '').toLowerCase(),\n      fecha_envio: cols.date_envio\n    }\n  };\n});"
      }
    },
    {
      "id": "d4e5f6a7-0004-0004-0004-000000000004",
      "name": "Loop: Por item",
