      "type": "n8n-nodes-base.code",
      "typeVersion": 2,
      "position": [1680, 140],
      "parameters": {
        "jsCode": "const campana    = $('PG: Obtener id_campana').item.json;\nconst contadores = $input.first().json;\nconst item       = $('Loop: Por item').item.json;\n\nconst total_enviados    = parseInt(contadores.total_enviados   || 0);\nconst total_delivered   = parseInt(contadores.total_delivered  || 0);\nconst total_respondidos = parseInt(contadores.total_respondidos|| 0);\n\n// ¿Hay que cerrar la campaña?\nconst es_notificacion = item.tipo === 'notificacion';\nconst fecha_envio_obj = campana.fecha_inicio_envio ? new Date(campana.fecha_inicio_envio) : null;\nconst horas_desde_envio = fecha_envio_obj ? (Date.now() - fecha_envio_obj.getTime()) / 3600000 : 0;\n\nconst completada = (total_respondidos > 0 && total_respondidos >= total_enviados)\n  || (es_notificacion && horas_desde_envio >= 48);\n\nreturn [{\n  json: {\n    monday_item_id: item.monday_item_id,\n    total_enviados,\n    total_delivered,\n    total_respondidos,\n    completada\n  }\n}];"
      }
