      "id": "e35970fc-e547-4df1-80cb-2da040989745",
      "name": "HTTP Conteo Total Delta",
      "type": "n8n-nodes-base.httpRequest",
      "typeVersion": 4.2,
      "position": [
        27744,
        1312
      ],
      "retryOnFail": true,
      "maxTries": 5,
      "waitBetweenTries": 5000,
      "credentials": {
        "mailjetEmailApi": {
          "id": "LTSvuIs0V4F6ScZE",
          "name": "Mailjet - Grupo Vemare"
        }
      }
    },
    {
      "parameters": {},
      "id": "db16d73d-1a54-4625-bd25-821da2b8874f",
      "name": "Merge Combinar Conteos",
      "type": "n8n-nodes-base.merge",
      "typeVersion": 3,
      "position": [
        27968,
        1408
      ]
    },
    {
      "parameters": {
        "jsCode": "// Compara conteo delta (LastActivityAt) vs total Mailjet vs total Postgres.\n// Si hay contactos nuevos en Mailjet → fuerza sync completa (ts_efectivo = 0).\n// Si solo hay actividad email → sync parcial con ts original.\n// Expone total_a_procesar para que Code Generar Páginas calcule las páginas correctas.\nconst items = $input.all();\nconst ctx   = $('Code Preparar Contexto').first().json;\n\nconst totales      = items.map(i => Number(i.json.Total ?? 0));\nconst deltaTotal   = Math.min(...totales); // filtrado por LastActivityAt → ≤ total\nconst mailjetTotal = Math.max(...totales); // sin filtro → el mayor\n\nconst hayNuevos      = mailjetTotal > ctx.pg_count;\nconst tsEfectivo     = hayNuevos ? 0 : ctx.last_sync_unix;\nconst totalAProcesar = hayNuevos ? mailjetTotal : deltaTotal;\nconst hayCambios     = totalAProcesar > 0;\n\nreturn [{\n  json: {\n    ts_efectivo:      tsEfectivo,\n    hay_cambios:      hayCambios,\n    total_a_procesar: totalAProcesar,\n    hay_nuevos:       hayNuevos,\n    delta_total:      deltaTotal,\n    mailjet_total:    mailjetTotal,\n    pg_count:         ctx.pg_count,\n    ts_inicio:        ctx.ts_inicio,\n    fecha_inicio:     ctx.fecha_inicio\n  }\n}];"
      },
      "id": "318bebb4-fa95-4055-ad69-481136627565",
      "name": "Code Decidir ts_efectivo",
      "type": "n8n-nodes-base.code",
      "typeVersion": 2,
      "position": [
        28192,
        1408
      ]
    },
    {
      "parameters": {
        "conditions": {
          "options": {
            "caseSensitive": true,
            "leftValue": "",
            "typeValidation": "strict",
            "version": 1
          },
          "conditions": [
            {
              "id": "filter-sync-01",
              "leftValue": "={{ $json.total_a_procesar }}",
              "rightValue": 0,
              "operator": {
                "type": "number",
                "operation": "gt"
              }
            }
          ],
          "combinator": "and"
        },
        "options": {}
      },
      "id": "076f8793-543b-4bf0-85f0-763f501d8325",
      "name": "[Filter] ¿Hay cambios?",
      "type": "n8n-nodes-base.filter",
      "typeVersion": 2,
      "position": [
        28416,
        1408
      ]
    },
    {
      "parameters": {
        "jsCode": "// Genera un item por página a paginar.\n// Usa total_a_procesar: puede ser delta o total Mailjet si hay nuevos contactos.\n// Propaga ts_efectivo como last_sync_unix para el filtro de HTTP GET Contacts Page.\nconst total = Number($json.total_a_procesar ?? 0);\nconst limit = 1000;\nconst pages = Math.max(1, Math.ceil(total / limit));\nconst ts_efectivo = $('Code Decidir ts_efectivo').first().json.ts_efectivo;\nreturn Array.from({ length: pages }, (_, i) => ({\n  json: { offset: i * limit, pageLimit: limit, last_sync_unix: ts_efectivo }\n}));"
      },
      "id": "68ff9c43-4d01-4ee9-91b7-9880e708d5dc",
      "name": "Code Generar Páginas",
      "type": "n8n-nodes-base.code",
      "typeVersion": 2,
      "position": [
        28640,
        1408
      ]
    },
    {
      "parameters": {
        "url": "https://api.mailjet.com/v3/REST/contact",
        "authentication": "predefinedCredentialType",
        "nodeCredentialType": "mailjetEmailApi",
        "sendQuery": true,
        "queryParameters": {
          "parameters": [
            {
              "name": "Limit",
              "value": "={{ $json.pageLimit }}"
            },
            {
              "name": "Offset",
              "value": "={{ $json.offset }}"
            },
            {
              "name": "LastActivityAt",
              "value": "={{ $json.last_sync_unix }}"
            }
          ]
        },
        "options": {
          "batching": {
            "batch": {
              "batchSize": 1,
              "batchInterval": 1500
            }
          }
        }
      },
      "id": "36c4244f-c82f-4d76-b418-9dd32d02f3f1",
      "name": "HTTP GET Contacts Page",
      "type": "n8n-nodes-base.httpRequest",
      "typeVersion": 4.2,
      "position": [
        28864,
        1408
      ],
      "retryOnFail": true,
      "maxTries": 5,
      "waitBetweenTries": 5000,
      "credentials": {
        "mailjetEmailApi": {
          "id": "LTSvuIs0V4F6ScZE",
          "name": "Mailjet - Grupo Vemare"
        }
      }
    },
    {
      "parameters": {
        "assignments": {
          "assignments": [
            {
              "id": "gc-01",
              "name": "_contacts",
              "value": "={{ $json.Data }}",
              "type": "array"
            },
            {
              "id": "gc-02",
