              "value": "={{ $('Code Generar Páginas').item.json.pageLimit }}",
              "type": "number"
            }
          ]
        },
        "options": {}
      },
      "id": "272dacdc-3a47-48cb-89f1-443712fbe7a6",
      "name": "Set Guardar Contexto",
      "type": "n8n-nodes-base.set",
      "typeVersion": 3.4,
      "position": [
        29088,
        1408
      ]
    },
    {
      "parameters": {
        "url": "https://api.mailjet.com/v3/REST/contactdata",
        "authentication": "predefinedCredentialType",
        "nodeCredentialType": "mailjetEmailApi",
        "sendQuery": true,
        "queryParameters": {
          "parameters": [
            {
              "name": "Limit",
              "value": "1000"
            },
            {
              "name": "Offset",
              "value": "={{ $node[\"Code Generar Páginas\"].json.offset }}"
            }
          ]
        },
        "options": {
          "batching": {
