    {
      "parameters": {
        "jsCode": "// Compara conteo delta (LastActivityAt) vs total Mailjet vs total Postgres.\n// Si hay contactos nuevos en Mailjet → fuerza sync completa (ts_efectivo = 0).\n// Si solo hay actividad email → sync parcial con ts original.\n// Expone total_a_procesar para que Code Generar Páginas calcule las páginas correctas.\nconst items = $input.all();\nconst ctx   = $('Code Preparar Contexto').first().json;\n\nconst totales      = items.map(i => Number(i.json.Total ?? 0));\nconst deltaTotal   = Math.min(...totales); // filtrado por LastActivityAt → ≤ total\nconst mailjetTotal = Math.max(...totales); // sin filtro → el mayor\n\nconst hayNuevos      = mailjetTotal > ctx.pg_count;\nconst tsEfectivo     = hayNuevos ? 0 : ctx.last_sync_unix;\nconst totalAProcesar = hayNuevos ? mailjetTotal : deltaTotal;\nconst hayCambios     = totalAProcesar > 0;\n\nreturn [{\n  json: {\n    ts_efectivo:      tsEfectivo,\n    hay_cambios:      hayCambios,\n    total_a_procesar: totalAProcesar,\n    hay_nuevos:       hayNuevos,\n    delta_total:      deltaTotal,\n    mailjet_total:    mailjetTotal,\n    pg_count:         ctx.pg_count,\n    ts_inicio:        ctx.ts_inicio,\n    fecha_inicio:     ctx.fecha_inicio\n  }\n}];"
      },
