    {
      "parameters": {
        "jsCode": "const now      = new Date().toISOString();\nconst contacts = $('Set Guardar Contexto').item.json._contacts || [];\nconst dataRows = $input.item.json.Data || [];\n\nconst fields = [\"nombre\",\"poblacion\",\"provincia\",\"zona_geografica\",\"zona_comercial\",\n  \"estado\",\"razon_social\",\"centro_reparto\",\"comercial_recambio\",\"comercial_equipamiento\",\n  \"comercial_pincar\",\"comercial_redes\",\"coordinador_recambio\",\"canal\",\"tipo_cliente\",\"red\",\n  \"sub_red\",\"subcanal\",\"division\",\"envio_promociones\",\"tipo_cliente_dto\",\"activo\",\"distribuidor\",\"cif\",\n  \"distribuidor_vemare\",\"distribuidor_transcose\",\"distribuidor_dieseliberia\",\"distribuidor_paher\",\n  \"codigo_isi_vemare\",\"codigo_isi_transcose\",\"codigo_isi_dieseliberia\",\"codigo_isi_paher\"];\n\nconst clasificarTelefono = (raw) => {\n  if (!raw) return { normalizado: '', tipo: 'vacio' };\n  let digits = String(raw).replace(/\\D/g, '');\n  if (digits.startsWith('0034') && digits.length === 13) digits = digits.slice(4);\n  else if (digits.startsWith('34') && digits.length === 11) digits = digits.slice(2);\n  if (digits.length !== 9) return { normalizado: '', tipo: 'invalido' };\n  const inicio = digits[0];\n  if (inicio === '6' || inicio === '7') return { normalizado: '+34' + digits, tipo: 'movil' };\n  if (inicio === '9' || inicio === '8') return { normalizado: '+34' + digits, tipo: 'fijo' };\n  return { normalizado: '', tipo: 'invalido' };\n};\n\nconst propMap = {};\nfor (const row of dataRows) {\n  const props = {};\n  for (const p of (row.Data || [])) props[p.Name] = p.Value;\n  propMap[String(row.ContactID)] = props;\n}\n\nreturn contacts.map(c => {\n  const props = propMap[String(c.ID)] || {};\n  const row = { id: c.ID, email: c.Email, last_sync: now };\n  for (const f of fields) row[f] = props[f] ?? '';\n  const t1 = clasificarTelefono(props.telefono_1);\n  const t2 = clasificarTelefono(props.telefono_2);\n  row.telefono_1      = t1.normalizado;\n  row.telefono_1_tipo = t1.tipo;\n  row.telefono_2      = t2.normalizado;\n  row.telefono_2_tipo = t2.tipo;\n  row.telefono_wa     = t1.tipo === 'movil' ? t1.normalizado\n                      : t2.tipo === 'movil' ? t2.normalizado\n                      : '';\n  row.listas_mailjet  = '';\n  return { json: row };\n});"
      },
