    {
      "parameters": {
        "jsCode": "// Recibe N responses de getcontactslists (1 por contacto del delta).\n// Construye el mismo formato que Code Consolidar Listas1 para reutilizar el Upsert.\nconst deltaItems = $('Code Unir y Normalizar').all();\nconst deltaIds   = $('Code IDs Delta para Listas').all();\nconst contactMap = {};\nfor (const item of deltaItems) {\n  contactMap[String(item.json.id)] = item.json;\n}\n\n// input.all() tiene 1 item por contacto con json.Data = [{ListID, Name, ...}]\nreturn $input.all().map((item, idx) => {\n  const id_mailjet = deltaIds[idx]?.json.idmailjet;\n  const c = contactMap[String(id_mailjet)] ?? {};\n  const listas_mailjet = (item.json.Data ?? [])\n    .map(l => (l.Name || String(l.ListID)))\n    .join(',');\n\n  return {\n    json: {\n      id_mailjet,\n      listas_mailjet,\n      email:                    c.email ?? '',\n      last_sync:                c.last_sync ?? '',\n      nombre:                   c.nombre ?? '',\n      poblacion:                c.poblacion ?? '',\n      razon_social:             c.razon_social ?? '',\n      provincia:                c.provincia ?? '',\n      zona_geografica:          c.zona_geografica ?? '',\n      zona_comercial:           c.zona_comercial ?? '',\n      estado:                   c.estado ?? '',\n      centro_reparto:           c.centro_reparto ?? '',\n      comercial_recambio:       c.comercial_recambio ?? '',\n      comercial_equipamiento:   c.comercial_equipamiento ?? '',\n      comercial_pincar:         c.comercial_pincar ?? '',\n      comercial_redes:          c.comercial_redes ?? '',\n      coordinador_recambio:     c.coordinador_recambio ?? '',\n      canal:                    c.canal ?? '',\n      tipo_cliente:             c.tipo_cliente ?? '',\n      red:                      c.red ?? '',\n      sub_red:                  c.sub_red ?? '',\n      subcanal:                 c.subcanal ?? '',\n      division:                 c.division ?? '',\n      envio_promociones:        c.envio_promociones ?? '',\n      tipo_cliente_dto:         c.tipo_cliente_dto ?? '',\n      activo:                   c.activo ?? '',\n      distribuidor:             c.distribuidor ?? '',\n      cif:                      c.cif ?? '',\n      telefono_1:               c.telefono_1 ?? '',\n      telefono_1_tipo:          c.telefono_1_tipo ?? '',\n      telefono_2:               c.telefono_2 ?? '',\n      telefono_2_tipo:          c.telefono_2_tipo ?? '',\n      telefono_wa:              c.telefono_wa ?? '',\n      distribuidor_vemare:      c.distribuidor_vemare ?? '',\n      distribuidor_transcose:   c.distribuidor_transcose ?? '',\n      distribuidor_dieseliberia: c.distribuidor_dieseliberia ?? '',\n      distribuidor_paher:       c.distribuidor_paher ?? '',\n      codigo_isi_vemare:        c.codigo_isi_vemare ?? '',\n      codigo_isi_transcose:     c.codigo_isi_transcose ?? '',\n      codigo_isi_dieseliberia:  c.codigo_isi_dieseliberia ?? '',\n      codigo_isi_paher:         c.codigo_isi_paher ?? ''\n    }\n  };\n});\n"
      },
