         "jsCode": "// v13: Lee IDs del delta desde staticData (guardados en Collapse → Fase 2).
// Emite {id_mailjet, listas_mailjet} — el upsert completo ya se hizo en Fase 1.
const sd = $getWorkflowStaticData('global');
const deltaIds = new Set((sd.delta_ids || []).map(String));

const listasMapa = {};
for (const item of $input.all()) {
  for (const row of (item.json.Data || [])) {
    const cid = String(row.ContactID);
    if (!deltaIds.has(cid)) continue;
    const lista = row.ContactsListName || String(row.ListID);
    if (!listasMapa[cid]) listasMapa[cid] = new Set();
    listasMapa[cid].add(lista);
  }
}

return [...deltaIds].map(cid => ({
  json: {
    id_mailjet:     Number(cid),
    listas_mailjet: listasMapa[cid] ? [...listasMapa[cid]].join(',') : ''
  }
}));"

         "jsCode": "// v13: Lee IDs desde staticData y emite {id_mailjet, listas_mailjet}.
// El upsert completo ya se hizo en Fase 1.
const sd = $getWorkflowStaticData('global');
const deltaIds = $('Code IDs Delta para Listas').all();

return $input.all().map((item, idx) => {
  const id_mailjet = deltaIds[idx]?.json.idmailjet;
  const listas_mailjet = (item.json.Data ?? [])
    .map(l => l.Name || String(l.ListID))
    .join(',');
  return { json: { id_mailjet: Number(id_mailjet), listas_mailjet } };
});"
